export async function getH3ImportsPreset () {
  const h3Exports = await resolveModuleExportNames('nitro/h3', {
    url: import.meta.url,
  })
  return {
    from: 'nitro/h3',
    imports: h3Exports.filter(n => !/^[A-Z]/.test(n) && n !== 'use'),
  }
}

